// Normaliza cada item do RSS para o formato de news_items.
// Regras da especificacao (cap. 12):
//  - deduplicar por URL canonica
//  - guardar fonte, autor e data
//  - resumo curto, NUNCA o artigo inteiro
//  - nada entra publicado: status 'pending' aguarda revisao humana

const LIMITE_RESUMO = 400;

/** Remove parametros de campanha e normaliza para comparar URLs. */
function normalizarUrl(bruta) {
  try {
    const u = new URL(String(bruta).trim());
    u.hash = '';
    u.hostname = u.hostname.toLowerCase().replace(/^www\./, '');
    u.protocol = 'https:';
    for (const p of [...u.searchParams.keys()]) {
      if (/^(utm_|fbclid|gclid|mc_cid|mc_eid|ref|source)/i.test(p)) u.searchParams.delete(p);
    }
    // A barra final fica no PATH, antes da query — tirar do pathname, nao da string toda.
    u.pathname = u.pathname.replace(/\/+$/, '');
    // Ordem dos parametros nao pode mudar a identidade da URL.
    u.searchParams.sort();
    return u.toString();
  } catch {
    return String(bruta || '').trim();
  }
}

function limparTexto(html) {
  return String(html || '')
    .replace(/<[^>]*>/g, ' ')
    .replace(/&nbsp;/g, ' ')
    .replace(/&amp;/g, '&')
    .replace(/&lt;/g, '<')
    .replace(/&gt;/g, '>')
    .replace(/&quot;/g, '"')
    .replace(/&#39;/g, "'")
    .replace(/\s+/g, ' ')
    .trim();
}

const saida = [];

for (const item of $input.all()) {
  const rss = item.json;

  // A fonte vem do node anterior, pareada pelo indice do item.
  let fonte = {};
  try {
    fonte = $('Buscar fontes ativas').all()[item.pairedItem?.item ?? 0]?.json ?? {};
  } catch {
    fonte = {};
  }

  const link = rss.link || rss.guid || '';
  if (!link) continue;

  const titulo = limparTexto(rss.title);
  if (!titulo) continue;

  const dataBruta = rss.isoDate || rss.pubDate || rss.published || null;
  const publicado = dataBruta ? new Date(dataBruta) : null;
  if (!publicado || isNaN(publicado.getTime())) continue;

  // So interessa noticia recente: nada com mais de 45 dias.
  const dias = (Date.now() - publicado.getTime()) / 86400000;
  if (dias > 45) continue;

  const resumoBruto = limparTexto(rss.contentSnippet || rss.summary || rss.content || '');
  const resumo = resumoBruto.length > LIMITE_RESUMO
    ? resumoBruto.slice(0, LIMITE_RESUMO).replace(/\s+\S*$/, '') + '...'
    : resumoBruto;

  saida.push({
    json: {
      source_id: fonte.id ?? null,
      titulo: titulo.slice(0, 300),
      resumo: resumo || null,
      canonical_url: link,
      url_hash: normalizarUrl(link),
      autor: limparTexto(rss.creator || rss.author || '') || null,
      publicado_em: publicado.toISOString(),
      categoria: fonte.categoria || 'ia',
      // Fonte oficial do fornecedor = anuncio. Qualquer outra = analise.
      tipo: fonte.confianca === 'oficial' ? 'anuncio' : 'analise',
      // NADA entra publicado automaticamente. Revisao humana decide.
      status: 'pending'
    }
  });
}

return saida;
